class Solution {
public:
    pair<int, int> findFloorCeil(const vector<int>& arr, int k) {
        int n = arr.size();
        int floor = -1, ceil = -1;

        // Binary search for floor
        int low = 0, high = n - 1;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (arr[mid] == k) {
                floor = arr[mid];
                ceil = arr[mid];
                return {floor, ceil};
            }
            else if (arr[mid] < k) {
                floor = arr[mid];
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        // Binary search for ceil
        low = 0, high = n - 1;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (arr[mid] >= k) {
                ceil = arr[mid];
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return {floor, ceil};
    }
};

