class Solution {
    findFloorCeil(arr, k) {
        let n = arr.length;
        let floor = -1, ceil = -1;

        // Binary search for floor
        let low = 0, high = n - 1;
        while (low <= high) {
            let mid = Math.floor((low + high) / 2);
            if (arr[mid] === k) {
                return [k, k];
            } else if (arr[mid] < k) {
                floor = arr[mid];
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        // Binary search for ceil
        low = 0;
        high = n - 1;
        while (low <= high) {
            let mid = Math.floor((low + high) / 2);
            if (arr[mid] >= k) {
                ceil = arr[mid];
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return [floor, ceil];
    }
}
